41	export function sortSessionsByLastModified(items: SessionMetadata[]): SessionMetadata[] {
42		return [...items].sort((left, right) => {
43			const byModified = right.lastModified.localeCompare(left.lastModified);
44			return byModified !== 0 ? byModified : right.id.localeCompare(left.id);
45		});
46	}
47	
48	export function filterSessions(items: SessionMetadata[], query: string): SessionMetadata[] {
49		const normalizedQuery = query.trim().toLowerCase();
50		if (!normalizedQuery) return items;
51		return items.filter((session) =>
52			[session.title, session.preview].some((value) =>
53				value.toLowerCase().includes(normalizedQuery),
54			),
55		);
56	}
57	
58	/**
59	 * Single source of session-list state shared by every session UI
60	 * (desktop panel and mobile sheet). Owns: metadata load + recency sort,
61	 * reload on `keating:sessions-changed`, the search filter, fork-tree
62	 * building, and rename/delete mutations.
63	 *
64	 * Talks only to the `sessions`/`keatingStorage` facades so it works
65	 * unchanged on the IndexedDB and P2P backends.
66	 */
67	export function useSessions(opts: UseSessionsOptions = {}): UseSessionsResult {
68		const [items, setItems] = useState<SessionMetadata[]>([]);
69		const [heroes, setHeroes] = useState<Map<string, ArtifactHero>>(new Map());
70		const [loading, setLoading] = useState(true);
71		const [error, setError] = useState<string | null>(null);
72		const [query, setQuery] = useState("");
73	
74		const reload = useCallback(async () => {
75			setLoading(true);
76			setError(null);
77			try {
78				const [metadata, heroMap] = await Promise.all([
79					sessions.getAllMetadata() as Promise<SessionMetadata[]>,
80					opts.withHeroes
81						? buildArtifactHeroMap(keatingStorage).catch(
82								() => new Map<string, ArtifactHero>(),
83							)
84						: Promise.resolve(new Map<string, ArtifactHero>()),
85				]);
86				setItems(sortSessionsByLastModified(metadata));
87				setHeroes(heroMap);
88			} catch (loadError) {
89				setError(
90					loadError instanceof Error ? loadError.message : "Failed to load sessions",
91				);
92				setItems([]);
93				setHeroes(new Map());
94			} finally {
95				setLoading(false);
96			}
97		}, [opts.withHeroes]);
98	
99		useEffect(() => {
100			let cancelled = false;
101			const runReload = async () => {
102				setLoading(true);
103				setError(null);
104				try {
105					const [metadata, heroMap] = await Promise.all([
106						sessions.getAllMetadata() as Promise<SessionMetadata[]>,
107						opts.withHeroes
108							? buildArtifactHeroMap(keatingStorage).catch(
109									() => new Map<string, ArtifactHero>(),
110								)
111							: Promise.resolve(new Map<string, ArtifactHero>()),
112					]);
113					if (cancelled) return;
114					setItems(sortSessionsByLastModified(metadata));
115					setHeroes(heroMap);
116				} catch (loadError) {
117					if (cancelled) return;
118					setError(
119						loadError instanceof Error ? loadError.message : "Failed to load sessions",
120					);
121					setItems([]);
122					setHeroes(new Map());
123				} finally {
124					if (!cancelled) setLoading(false);
125				}
126			};
127			void runReload();
128			const onChanged = () => void runReload();
129			window.addEventListener("keating:sessions-changed", onChanged);
130			return () => {
131				cancelled = true;
132				window.removeEventListener("keating:sessions-changed", onChanged);
133			};
134		}, [opts.withHeroes]);
135	
136		const filtered = useMemo(() => filterSessions(items, query), [items, query]);
137		const flatResults = useMemo(() => {
138			if (!query.trim()) return null;
139			return filtered.slice(0, opts.flatLimit ?? 50);
140		}, [filtered, opts.flatLimit, query]);
141		const roots = useMemo(() => buildSessionTree(items), [items]);
142	
143		const rename = useCallback(
144			async (id: string, title: string, aiGeneratedTitle?: boolean) => {
145				await updateSessionTitle(id, title, aiGeneratedTitle);
146			},
147			[],
148		);
149	
150		const remove = useCallback(async (id: string) => {
151			await sessions.deleteSession(id);
152			notifySessionsChanged();
153		}, []);
154	
155		return {
156			items,
157			loading,
158			error,
159			query,
160			setQuery,
161			flatResults,
162			roots,
163			heroes,
164			reload,
165			rename,
166			remove,
167		};
168	}

